  CLASS
	NAME "Alitud (m.s.n.m)"
  EXPRESSION ([pixel] = -99999)
  COLOR -1 -1 -1
  END
  CLASS
	NAME "0 - 500"
  EXPRESSION ([pixel] >= 0 AND [pixel] < 500)
