  COLOR 176 219 112
  END
  CLASS
	NAME "1500 - 2000"
  EXPRESSION ([pixel] >= 1500 AND [pixel] <= 2000)
  COLOR 10 138 55
  END 
  CLASS
	NAME "2000 - 2500"
  EXPRESSION ([pixel] >= 2000 AND [pixel] <= 2500)
  COLOR 147 160 42
  END
  CLASS
	NAME "2500 - 3000"
  EXPRESSION ([pixel] >= 2500 AND [pixel] <= 3000)
  COLOR 227 139 11
  END 
  CLASS
	NAME "3000 - 3500"
  EXPRESSION ([pixel] >= 3000 AND [pixel] <= 3500)
